#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 5e5 + 5;
ll x[MAXN], a[MAXN], n, sum = 0, fsum = 0;
int main(void)
{
	cin >> n;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
	}
	for (int i = 2; i <= n; ++i)
	{
		if (a[i] - a[i - 1] > 0)sum += a[i] - a[i - 1];
		else fsum -= (a[i] - a[i - 1]);
	}
	cout << max(sum, fsum) << '\n' << abs(sum - fsum) + 1;
	return false;
}
